/// Parse FretboardNavigation from a string. Returns Ok or Error.
let parse (input: string) : Result<NavigationCommandNode, string> =
    match run (navigationCommandParser .>> eof) input with
    | Success (v, _, _) -> Result.Ok v
    | Failure (msg, _, _) -> Result.Error msg
